import { useState } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { useQueryClient } from "@tanstack/react-query";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { Search, Loader2, MapPin, Import, BookOpen, ImageIcon, AlertTriangle, CheckCircle2 } from "lucide-react";
import { Progress } from "@/components/ui/progress";
import { Input } from "@/components/ui/input";

interface DiscoveredRestaurant {
  name: string;
  address: string;
  cuisine_type: string;
  city: string;
  verified?: boolean;
  corrected_address?: string;
}

const CITIES = [
  "all",
  "Lisboa", "Porto", "Faro", "Coimbra", "Braga", "Aveiro", "Leiria",
  "Setúbal", "Almada", "Amadora", "Cascais", "Sintra", "Oeiras", "Odivelas",
  "Funchal", "Guimarães", "Viseu", "Évora", "Vila Nova de Gaia", "Matosinhos",
  "Barreiro", "Seixal", "Loures", "Portimão", "Albufeira", "Lagos",
  "Caldas da Rainha", "Torres Vedras", "Santarém", "Viana do Castelo",
];

export function DiscoverRestaurantsDialog({ trigger }: { trigger: React.ReactNode }) {
  const { t } = useTranslation();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [open, setOpen] = useState(false);
  const [selectedCity, setSelectedCity] = useState("all");
  const [searchSource, setSearchSource] = useState<"google_places" | "google_plus_ai" | "general" | "ubereats_perplexity" | "ubereats_firecrawl">("google_places");
  const [searchKeyword, setSearchKeyword] = useState("");
  const [isSearching, setIsSearching] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [isGeneratingStories, setIsGeneratingStories] = useState(false);
  const [discovered, setDiscovered] = useState<DiscoveredRestaurant[]>([]);
  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
  const [searchStats, setSearchStats] = useState<{
    total_discovered: number;
    duplicates_filtered: number;
    city_results?: Record<string, number>;
    verified_count?: number;
    search_error?: string;
  } | null>(null);
  const [importResults, setImportResults] = useState<{
    imported: number;
    failed: number;
  } | null>(null);
  const [importedIds, setImportedIds] = useState<string[]>([]);
  const [storyProgress, setStoryProgress] = useState({ current: 0, total: 0 });
  const [storyResult, setStoryResult] = useState<{ processed: number } | null>(null);
  const [isFetchingPhotos, setIsFetchingPhotos] = useState(false);
  const [photoProgress, setPhotoProgress] = useState({ current: 0, total: 0 });
  const [photoResult, setPhotoResult] = useState<{ success: number; failed: number } | null>(null);

  const handleSearch = async () => {
    setIsSearching(true);
    setDiscovered([]);
    setSelectedItems(new Set());
    setSearchStats(null);
    setImportResults(null);

    try {
      const { data, error } = await supabase.functions.invoke("discover-asian-restaurants", {
        body: { city: selectedCity, mode: "search", keyword: searchKeyword.trim() || undefined, source: searchSource },
      });

      if (error) throw error;

      setDiscovered(data.restaurants || []);
      setSearchStats({
        total_discovered: data.total_discovered,
        duplicates_filtered: data.duplicates_filtered,
        city_results: data.city_results,
        verified_count: data.verified_count,
        search_error: data.search_error,
      });
      // Select only verified by default; unverified are deselected
      const restaurants: DiscoveredRestaurant[] = data.restaurants || [];
      setSelectedItems(new Set(restaurants.map((r, i) => r.verified !== false ? i : -1).filter(i => i >= 0)));
    } catch (e) {
      toast({
        title: "搜索失败",
        description: e instanceof Error ? e.message : "Unknown error",
        variant: "destructive",
      });
    } finally {
      setIsSearching(false);
    }
  };

  const handleImport = async () => {
    if (selectedItems.size === 0) return;
    setIsImporting(true);

    try {
      const selectedRestaurants = [...selectedItems].map(i => {
        const r = discovered[i];
        // Use corrected address if available and original was unverified
        return {
          ...r,
          address: (r.verified === false && r.corrected_address) ? r.corrected_address : r.address,
        };
      });

      const { data, error } = await supabase.functions.invoke("discover-asian-restaurants", {
        body: { mode: "import", restaurants: selectedRestaurants },
      });

      if (error) throw error;

      setImportResults({ imported: data.imported, failed: data.failed });
      // Track imported IDs for scoped story/photo generation
      const successIds = (data.results || []).filter((r: any) => r.success).map((r: any) => r.id);
      setImportedIds(successIds);
      queryClient.invalidateQueries({ queryKey: ["admin-restaurants"] });

      toast({
        title: "导入完成",
        description: `成功导入 ${data.imported} 家餐厅`,
      });
    } catch (e) {
      toast({
        title: "导入失败",
        description: e instanceof Error ? e.message : "Unknown error",
        variant: "destructive",
      });
    } finally {
      setIsImporting(false);
    }
  };

  const handleGenerateStories = async () => {
    setIsGeneratingStories(true);
    setStoryProgress({ current: 0, total: 0 });
    setStoryResult(null);

    try {
      if (importedIds.length === 0) {
        toast({ title: "没有已导入的餐厅可生成故事" });
        setIsGeneratingStories(false);
        return;
      }

      const total = importedIds.length;
      setStoryProgress({ current: 0, total });

      const batchSize = 5;
      let processed = 0;

      for (let i = 0; i < total; i += batchSize) {
        const batch = importedIds.slice(i, i + batchSize);

        const { data, error } = await supabase.functions.invoke("generate-store-stories", {
          body: { restaurant_ids: batch, mode: "story", no_brand: true },
        });

        if (error) {
          console.error("Story generation error:", error);
          continue;
        }

        processed += data?.updated || 0;
        setStoryProgress({ current: Math.min(i + batchSize, total), total });

        if (data?.processed === 0) break;

        await new Promise(r => setTimeout(r, 2000));
      }

      setStoryResult({ processed });
      toast({
        title: "✅ 建筑故事生成完成",
        description: `已为 ${processed} 家餐厅生成建筑故事`,
      });
    } catch (e) {
      toast({
        title: "生成失败",
        description: e instanceof Error ? e.message : "Unknown error",
        variant: "destructive",
      });
    } finally {
      setIsGeneratingStories(false);
    }
  };

  const handleFetchPhotos = async () => {
    setIsFetchingPhotos(true);
    setPhotoProgress({ current: 0, total: 0 });
    setPhotoResult(null);

    try {
      if (importedIds.length === 0) {
        toast({ title: "没有已导入的餐厅可抓取照片" });
        setIsFetchingPhotos(false);
        return;
      }

      const total = importedIds.length;
      setPhotoProgress({ current: 0, total });

      const batchSize = 5;
      let successCount = 0;
      let failedCount = 0;

      for (let i = 0; i < total; i += batchSize) {
        const ids = importedIds.slice(i, i + batchSize);

        // Try Google Places first, then fallback to Street View
        const { data, error } = await supabase.functions.invoke("fetch-place-photos", {
          body: { restaurant_ids: ids, limit: batchSize, photo_index: 0 },
        });

        if (!error && data?.results) {
          const batchSuccess = data.results.filter((r: any) => r.status === "success").length;
          const batchNoPhoto = data.results.filter((r: any) => r.status === "no_photos").map((r: any) => r.id);
          successCount += batchSuccess;

          // Fallback: try street view for restaurants with no Google photos
          if (batchNoPhoto.length > 0) {
            const { data: svData } = await supabase.functions.invoke("fetch-place-photos", {
              body: { restaurant_ids: batchNoPhoto, limit: batchNoPhoto.length, use_street_view: true },
            });
            if (svData?.results) {
              successCount += svData.results.filter((r: any) => r.status === "success").length;
              failedCount += svData.results.filter((r: any) => r.status !== "success").length;
            }
          }

          failedCount += data.results.filter((r: any) => r.status !== "success" && !batchNoPhoto.includes(r.id)).length;
        }

        setPhotoProgress({ current: Math.min(i + batchSize, total), total });
        await new Promise(r => setTimeout(r, 1000));
      }

      setPhotoResult({ success: successCount, failed: failedCount });
      toast({
        title: "✅ 照片抓取完成",
        description: `成功 ${successCount} 家，失败 ${failedCount} 家`,
      });
      queryClient.invalidateQueries({ queryKey: ["admin-restaurants"] });
    } catch (e) {
      toast({
        title: "抓取失败",
        description: e instanceof Error ? e.message : "Unknown error",
        variant: "destructive",
      });
    } finally {
      setIsFetchingPhotos(false);
    }
  };

  const toggleItem = (index: number) => {
    setSelectedItems(prev => {
      const next = new Set(prev);
      if (next.has(index)) next.delete(index);
      else next.add(index);
      return next;
    });
  };

  const toggleAll = () => {
    if (selectedItems.size === discovered.length) {
      setSelectedItems(new Set());
    } else {
      setSelectedItems(new Set(discovered.map((_, i) => i)));
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>{trigger}</DialogTrigger>
      <DialogContent className="max-w-2xl max-h-[85vh] flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Search className="h-5 w-5" />
            搜索亚洲餐厅 (葡萄牙)
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4 flex-1 overflow-hidden flex flex-col">
          {/* City & keyword selection */}
          <div className="flex flex-col gap-2">
            <div className="flex gap-2">
              <Select value={selectedCity} onValueChange={setSelectedCity}>
                <SelectTrigger className="w-[140px]">
                  <SelectValue placeholder="选择城市" />
                </SelectTrigger>
                <SelectContent>
                  {CITIES.map(city => (
                    <SelectItem key={city} value={city}>
                      {city === "all" ? "🇵🇹 全部城市" : city}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <Select value={searchSource} onValueChange={(v: any) => setSearchSource(v)}>
                <SelectTrigger className="w-[200px]">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="google_places">📍 Google Places (推荐)</SelectItem>
                  <SelectItem value="google_plus_ai">📍+🤖 Google + AI补充</SelectItem>
                  <SelectItem value="general">🔍 AI通用搜索</SelectItem>
                  <SelectItem value="ubereats_perplexity">🟢 Uber Eats (AI)</SelectItem>
                  <SelectItem value="ubereats_firecrawl">🔥 Uber Eats (抓取)</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="flex gap-2">
              <Input
                placeholder="搜索关键词（如：ramen, sushi, 火锅）"
                value={searchKeyword}
                onChange={(e) => setSearchKeyword(e.target.value)}
                className="flex-1"
                onKeyDown={(e) => e.key === "Enter" && !isSearching && handleSearch()}
              />
              <Button onClick={handleSearch} disabled={isSearching}>
                {isSearching ? (
                  <><Loader2 className="mr-2 h-4 w-4 animate-spin" />搜索中...</>
                ) : (
                  <><Search className="mr-2 h-4 w-4" />搜索</>
                )}
              </Button>
            </div>
          </div>

          {/* Search stats */}
          {searchStats && (
            <div className="space-y-2">
              <div className="flex gap-4 text-sm text-muted-foreground flex-wrap">
                <span>发现: {searchStats.total_discovered}</span>
                <span>已存在: {searchStats.duplicates_filtered}</span>
                <span className="text-foreground font-medium">新增: {discovered.length}</span>
                {searchStats.verified_count !== undefined && (
                  <span className="text-emerald-600 dark:text-emerald-400 font-medium flex items-center gap-1">
                    <CheckCircle2 className="h-3.5 w-3.5" />
                    已验证: {searchStats.verified_count}/{discovered.length}
                  </span>
                )}
              </div>
              {searchStats.search_error && (
                <div className="p-3 rounded-md bg-destructive/10 border border-destructive/20 text-sm text-destructive flex items-start gap-2">
                  <AlertTriangle className="h-4 w-4 mt-0.5 flex-shrink-0" />
                  <div>
                    <p className="font-medium">Google Places API 错误</p>
                    <p className="text-xs mt-1 opacity-80">{searchStats.search_error}</p>
                    <p className="text-xs mt-1">请在 <a href="https://console.cloud.google.com/apis/library/places-backend.googleapis.com" target="_blank" rel="noopener noreferrer" className="underline font-medium">Google Cloud Console</a> 启用 Places API</p>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Results list */}
          {discovered.length > 0 && (
            <>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Checkbox
                    checked={selectedItems.size === discovered.length}
                    onCheckedChange={toggleAll}
                  />
                  <span className="text-sm">全选 ({selectedItems.size}/{discovered.length})</span>
                </div>
                <div className="flex gap-2">
                  <Button size="sm" onClick={handleImport} disabled={isImporting || selectedItems.size === 0}>
                    {isImporting ? (
                      <><Loader2 className="mr-2 h-4 w-4 animate-spin" />导入中...</>
                    ) : (
                      <><Import className="mr-2 h-4 w-4" />导入 ({selectedItems.size})</>
                    )}
                  </Button>
                </div>
              </div>

              <div className="flex-1 min-h-0 max-h-[50vh] border rounded-md overflow-y-auto">
                <div className="p-2 space-y-1">
                  {discovered.map((r, i) => (
                    <div
                      key={i}
                      className={`flex items-start gap-2 p-2 rounded hover:bg-muted/50 cursor-pointer ${r.verified === false ? "opacity-60 border border-dashed border-destructive/30" : ""}`}
                      onClick={() => toggleItem(i)}
                    >
                      <Checkbox checked={selectedItems.has(i)} className="mt-1" />
                      <div className="flex-1 min-w-0">
                        <div className="font-medium text-sm truncate flex items-center gap-1.5">
                          {r.verified === false ? (
                            <AlertTriangle className="h-3.5 w-3.5 text-destructive flex-shrink-0" />
                          ) : r.verified === true ? (
                            <CheckCircle2 className="h-3.5 w-3.5 text-emerald-600 dark:text-emerald-400 flex-shrink-0" />
                          ) : null}
                          <span className="truncate">{r.name}</span>
                        </div>
                        <div className="text-xs text-muted-foreground flex items-center gap-1">
                          <MapPin className="h-3 w-3 flex-shrink-0" />
                          <span className={`truncate ${r.verified === false ? "line-through" : ""}`}>{r.address}</span>
                        </div>
                        {r.verified === false && r.corrected_address && (
                          <div className="text-xs text-emerald-600 dark:text-emerald-400 flex items-center gap-1 mt-0.5">
                            <MapPin className="h-3 w-3 flex-shrink-0" />
                            <span className="truncate">→ {r.corrected_address}</span>
                          </div>
                        )}
                      </div>
                      <Badge variant="secondary" className="text-xs flex-shrink-0">
                        {r.cuisine_type}
                      </Badge>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}

          {/* Import results */}
          {importResults && (
            <div className="p-3 rounded-md bg-muted/50 space-y-2">
              <div className="text-sm font-medium">
                ✅ 已导入 {importResults.imported} 家 | ❌ 失败 {importResults.failed} 家
              </div>

              {storyResult ? (
                <div className="p-2 rounded-md bg-green-500/10 border border-green-500/20 text-sm text-green-700 dark:text-green-400 font-medium">
                  🎉 建筑故事生成完成！共处理 {storyResult.processed} 家餐厅
                </div>
              ) : (
                <Button
                  size="sm"
                  variant="outline"
                  onClick={handleGenerateStories}
                  disabled={isGeneratingStories}
                >
                  {isGeneratingStories ? (
                    <><Loader2 className="mr-2 h-4 w-4 animate-spin" />生成建筑故事中...</>
                  ) : (
                    <><BookOpen className="mr-2 h-4 w-4" />为已导入餐厅生成故事 ({importedIds.length})</>
                  )}
                </Button>
              )}

              {isGeneratingStories && storyProgress.total > 0 && (
                <div className="space-y-1">
                  <Progress value={(storyProgress.current / storyProgress.total) * 100} />
                  <div className="text-xs text-muted-foreground">
                    {storyProgress.current} / {storyProgress.total}
                  </div>
                </div>
              )}

              {/* Photo fetch section */}
              {photoResult ? (
                <div className="p-2 rounded-md bg-primary/10 border border-primary/20 text-sm text-primary font-medium">
                  📷 照片抓取完成！成功 {photoResult.success} 家，失败 {photoResult.failed} 家
                </div>
              ) : (
                <Button
                  size="sm"
                  variant="outline"
                  onClick={handleFetchPhotos}
                  disabled={isFetchingPhotos}
                >
                  {isFetchingPhotos ? (
                    <><Loader2 className="mr-2 h-4 w-4 animate-spin" />抓取照片中...</>
                  ) : (
                    <><ImageIcon className="mr-2 h-4 w-4" />为已导入餐厅抓取照片 ({importedIds.length})</>
                  )}
                </Button>
              )}

              {isFetchingPhotos && photoProgress.total > 0 && (
                <div className="space-y-1">
                  <Progress value={(photoProgress.current / photoProgress.total) * 100} />
                  <div className="text-xs text-muted-foreground">
                    {photoProgress.current} / {photoProgress.total}
                  </div>
                </div>
              )}
            </div>
          )}

          {isSearching && (
            <div className="flex flex-col items-center justify-center py-8 gap-3">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
              <p className="text-sm text-muted-foreground">
                正在搜索{selectedCity === "all" ? "全葡萄牙" : selectedCity}的亚洲餐厅...
              </p>
              {selectedCity === "all" && (
                <p className="text-xs text-muted-foreground">搜索30个城市可能需要1-2分钟</p>
              )}
            </div>
          )}

          {/* Standalone photo fetch (always visible when no import results) */}
          {!importResults && !isSearching && discovered.length === 0 && (
            <div className="p-3 rounded-md bg-muted/50 space-y-2">
              <p className="text-sm text-muted-foreground">快捷工具</p>
              {photoResult ? (
                <div className="p-2 rounded-md bg-primary/10 border border-primary/20 text-sm text-primary font-medium">
                  📷 照片抓取完成！成功 {photoResult.success} 家，失败 {photoResult.failed} 家
                </div>
              ) : (
                <Button
                  size="sm"
                  variant="outline"
                  onClick={handleFetchPhotos}
                  disabled={isFetchingPhotos}
                >
                  {isFetchingPhotos ? (
                    <><Loader2 className="mr-2 h-4 w-4 animate-spin" />抓取照片中...</>
                  ) : (
                    <><ImageIcon className="mr-2 h-4 w-4" />为无配图餐厅抓取 Google 照片</>
                  )}
                </Button>
              )}
              {isFetchingPhotos && photoProgress.total > 0 && (
                <div className="space-y-1">
                  <Progress value={(photoProgress.current / photoProgress.total) * 100} />
                  <div className="text-xs text-muted-foreground">
                    {photoProgress.current} / {photoProgress.total}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}
